INSERT INTO `categories` (`id`, `title`, `slug`, `summary`, `photo`, `is_parent`, `parent_id`, `added_by`, `status`, `created_at`, `updated_at`) VALUES
(14, 'Spindle, Suspension & Steering', 'spindle-suspension-steering', '<p>A range of precision-manufactured front spindle assemblies, bearings, seals, and hardware designed for reliable steering stability and long-lasting performance. Engineered for accurate fit and durability, suitable for OEM and aftermarket applications.</p>', NULL, 1, NULL, NULL, 'active', '2026-03-03 15:29:03', '2026-03-03 15:29:03'),
(15, 'Cotter Pins', 'cotter-pins', '<p><div aria-hidden=\"true\" data-edge=\"true\" class=\"pointer-events-none h-px w-px absolute bottom-0\"></div></p><div class=\"flex flex-col text-sm pb-25\"><article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" tabindex=\"-1\" dir=\"auto\" data-turn-id=\"request-WEB:613fb178-6872-4321-a555-8f9f06f3974c-3\" data-testid=\"conversation-turn-8\" data-scroll-anchor=\"true\" data-turn=\"assistant\"><div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\"><div tabindex=\"-1\" class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\"><div class=\"flex max-w-full flex-col grow\"><div data-message-author-role=\"assistant\" data-message-id=\"3f126024-72a4-4eb1-805d-44d222706709\" dir=\"auto\" data-message-model-slug=\"gpt-5-2\" class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\"><div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\"><div class=\"markdown prose dark:prose-invert w-full wrap-break-word dark markdown-new-styling\"><p data-start=\"17\" data-end=\"243\" data-is-last-node=\"\" data-is-only-node=\"\">High-quality cotter pins designed to securely lock nuts and fasteners in place, preventing loosening under vibration and load. Manufactured for durability and reliable performance across automotive and industrial applications.</p></div></div></div></div><div class=\"z-0 flex min-h-[46px] justify-start\"></div></div></div></article></div>', NULL, 0, 14, NULL, 'active', '2026-03-03 15:30:06', '2026-03-03 15:30:06'),
(16, 'Mounting Hardware', 'mounting-hardware', NULL, NULL, 1, NULL, NULL, 'active', '2026-03-03 15:57:46', '2026-03-03 15:57:46'),
