(18, 'Clutch System (mechanical)', 'clutch-system-mechanical', '<p data-start=\"369\" data-end=\"502\">Clutch rods are linkage components that transfer motion from the pedal or actuator to the clutch release mechanism.</p><p data-start=\"630\" data-end=\"748\">Clutch bolts are high-strength fasteners used to secure clutch assemblies to the flywheel or engine.</p>', NULL, 1, NULL, NULL, 'active', '2026-03-03 16:02:55', '2026-03-03 16:02:55'),
(19, 'Clutch Rods & Clutch Bolts', 'clutch-rods-clutch-bolts', '<p data-start=\"630\" data-end=\"748\">Clutch bolts are high-strength fasteners used to secure clutch assemblies to the flywheel or engine.</p>', NULL, 0, 18, NULL, 'active', '2026-03-03 16:04:27', '2026-03-03 16:04:45'),
