INSERT INTO `settings` (`id`, `description`, `short_des`, `logo`, `photo`, `address`, `phone`, `email`, `created_at`, `updated_at`) VALUES
(1, 'Dr Auto Store is a trusted automotive solutions provider offering high-quality spare parts, genuine accessories, and reliable vehicle maintenance products. We specialize in delivering durable auto components for cars, bikes, and commercial vehicles, ensuring performance, safety, and long-term value. Our store focuses on customer satisfaction by providing authentic products, competitive pricing, and expert guidance for every automotive need. With a commitment to quality standards and timely availability, Dr Auto Store aims to become a dependable name in the auto parts industry. Whether customers need engine components, electrical parts, suspension items, or routine accessories, we strive to support smooth vehicle operations through professional service and dependable automotive supplies.', 'Danyal Autos&nbsp;', 'https://drautos.store//storage/photos/1/Nakash_Raza_make_this_logo_in_full_scale_image_f1401921-ac67-4fd4-8086-4408cfb179f4.png', '/storage/photos/1/car1.jpg', '12-BUTT MARKET BADAMI BAGH  LAHORE', '+923042000274', 'drautostore@gmail.com', NULL, '2026-03-02 21:25:22');
